import requests
import time

class DataFetcher:
    def fetch_user(self, user_id):
        response = requests.get(f"https://api.example.com/users/{user_id}")
        return response.json()

    def process_users(self, user_ids):
        results = []
        for user_id in user_ids:
            user = self.fetch_user(user_id)
            results.append(user)
        return results
